Implement chat.stream() — fetch + ReadableStream loop with manual SSE parsing. Per frontend-spec.md §4.

In frontend/app/src/lib/api/chat.ts:
  export async function stream(req, signal, handlers) {
      const res = await fetch("/api/v1/chat/stream", {
          method: "POST",
          headers: {"Content-Type":"application/json"},
          body: JSON.stringify(req),
          signal,
          credentials: "include",
      });
      if (!res.ok || !res.body) throw new Error(...);
      const reader = res.body.getReader();
      const decoder = new TextDecoder();
      let buffer = "";
      try {
          while (true) {
              const { value, done } = await reader.read();
              if (done) break;
              buffer += decoder.decode(value, { stream: true });
              let idx;
              while ((idx = buffer.indexOf("\n\n")) >= 0) {
                  const block = buffer.slice(0, idx);
                  buffer = buffer.slice(idx + 2);
                  const ev = parseSSEBlock(block);
                  if (ev) handlers.onEvent(ev);
              }
          }
      } catch (err) {
          if ((err as Error).name === "AbortError") return; // expected
          handlers.onError?.(err as Error);
      } finally {
          handlers.onClose?.();
      }
  }

